module RefModule(clk, rst, out);input clk;
   input rst;
   output [3:0] out;
  wire _tap_clk = clk & {1{1'b1}};

   reg [3:0] counter;
   assign out =  counter;

   always @(posedge clk) begin
      if (rst) begin
         counter <= 0;
      end else begin
         counter <= counter +1;
      end
   end
endmodule
